#!/usr/bin/env bash
# topic-1.sh — 学习 决策助手 for AI自适应学习.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI自适应学习"
TOPIC="学习"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 5 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 学习 主题下的 playbook 规则组合成交互树。

基于 5 条规则:
  • 如果 要判断一个「自适应学习」产品是否名副其实 → 则 追问三个问题: (a) 是否维护逐学生概率知识状态? (b) 内容选择是否基于该状态的实时估计? (c) 是否有学习效果
  • 如果 需要选择知识追踪算法 → 则 按数据量分层: <1万交互 → BKT (参数少, 小样本稳定); 1-100万 → PFA/LFA (线性回归, 可解
  • 如果 学习内容需要长期记忆保持 → 则 (语言词汇/医学术语/法律条文/认证知识点), 则必须嵌入间隔重复, 且优先选 FSRS v5+ 而非 SM-2 — o
  • 如果 面向美国 K-12 市场销售自适应学习产品 → 则 必须满足 FERPA + COPPA (若 <13 岁) + 州级学生数据隐私法 (各州不同, 约 40 州有专门立法,
  • 如果 知识组件 (KC) 分解不确定该多细 → 则 遵循 Koedinger 的 KLI 框架: 先用专家判断做初始分解 → 在 DataShop 等平台上用学习曲线分析验

相关心智模型:
  • 追踪-适应闭环 (Trace-then-Adapt Loop): 自适应学习的核心运作模式是「持续估计学生的潜在知识状态 → 基于估计选择最优下一步教学动作」的概率闭环, 而非简单的分数累加-推荐
  • 粒度决定效果 (Granularity Determines Effectiveness): 自适应的粒度越细 (从课程级→单元级→步骤级→子步骤级), 效果越接近人类一对一辅导 — VanLehn (2011) meta-review 证实步骤级 ITS 效果量约 d=0.76 (业内估),

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "要判断一个「自适应学习」产品是否名副其实"
  "需要选择知识追踪算法"
  "学习内容需要长期记忆保持"
  "面向美国 K-12 市场销售自适应学习产品"
  "知识组件 (KC) 分解不确定该多细"
)
declare -a RULE_ACTIONS=(
  "追问三个问题: (a) 是否维护逐学生概率知识状态? (b) 内容选择是否基于该状态的实时估计? (c) 是否有学习效果的独立 RCT 证据? 三项都否 = 只是分支逻辑的「伪自适应」"
  "按数据量分层: <1万交互 → BKT (参数少, 小样本稳定); 1-100万 → PFA/LFA (线性回归, 可解释); >100万 → DKT/AKT (深度学习, 但需 GPU 训练 + 可解释性补丁)"
  "(语言词汇/医学术语/法律条文/认证知识点), 则必须嵌入间隔重复, 且优先选 FSRS v5+ 而非 SM-2 — open-spaced-repetition 在约 500M+ 条复习记录 (业内估) 的 benchmark 上已证明 FSRS 在所有主要指标上优于 SM-2"
  "必须满足 FERPA + COPPA (若 <13 岁) + 州级学生数据隐私法 (各州不同, 约 40 州有专门立法, 业内估 SDPC 2024) + ESSA 证据分级 (Tier I-IV, 学区采购越来越要求 Tier II 以上 RCT 证据)"
  "遵循 Koedinger 的 KLI 框架: 先用专家判断做初始分解 → 在 DataShop 等平台上用学习曲线分析验证 → 如果学习曲线不下降说明 KC 粒度不对 → 迭代"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
